Code.Terraform:
```hcl
# InitialInstanceCount > 1 の SageMaker エンドポイント設定
resource "aws_sagemaker_endpoint_configuration" "<example_resource_name>" {
  production_variants {
    variant_name           = "<example_resource_name>"
    model_name             = "<example_resource_name>"
    instance_type          = "ml.m5.large"
    initial_instance_count = 2 # 重要: バリアントがチェックに合格するように、2以上に設定してください
  }
}
```
